import { defineConfig, loadEnv } from 'vite'
import react from '@vitejs/plugin-react'
import fs from 'node:fs'

// https://vitejs.dev/config/
export default defineConfig(({ mode }) => {
  const env = loadEnv(mode, process.cwd(), '')
  const authProxyUrl = env.VITE_AUTH_PROXY_URL || 'http://localhost:8080'
  const envOutDir = env.VITE_OUT_DIR

  const chooseOutDir = () => {
    if (envOutDir) return envOutDir
    try {
      // If dist exists but is not writable (e.g. generated by root in docker), fall back.
      fs.mkdirSync('dist', { recursive: true })
      fs.accessSync('dist', fs.constants.W_OK)
      return 'dist'
    } catch {
      return 'dist-local'
    }
  }

  return {
    plugins: [react()],
    server: {
      host: '0.0.0.0', // Доступ извне контейнера
      port: 3000,
      proxy: {
        // Experiment-service API and Telemetry ingest (through auth-proxy)
        '/api': {
          target: authProxyUrl,
          changeOrigin: true,
        },
        // Auth-service projects API (through auth-proxy)
        '/projects': {
          target: authProxyUrl,
          changeOrigin: true,
        },
      },
    },
    build: {
      outDir: chooseOutDir(),
    },
    test: {
      globals: true,
      environment: 'jsdom',
      setupFiles: './src/setupTests.ts',
      css: true,
      testTimeout: 10000,
      hookTimeout: 10000,
      reporters: process.env.CI ? ['verbose'] : ['default'],
      coverage: {
        provider: 'v8',
        reporter: ['text', 'html', 'lcov'],
        reportsDirectory: './coverage',
        include: ['src/**/*.{ts,tsx}'],
        exclude: [
          'src/**/*.test.{ts,tsx}',
          'src/**/*.spec.{ts,tsx}',
          'src/setupTests.ts',
          'src/main.tsx',
          'src/vite-env.d.ts',
          'src/**/__mocks__/**',
        ],
        // Ratchet floor — start conservative, raise as more tests land.
        // Plan target: 65% lines (see docs/coverage plan).
        thresholds: {
          lines: 50,
          statements: 50,
          functions: 45,
          branches: 50,
        },
      },
    },
  }
})

